```

**filter_views** — `/home/aditya/projects/alpauls-ats/src/db-schemas/filter-view.ts`:
```ts
// line 32
id: text().primaryKey(),
```

### C. Explicit `crypto.randomUUID()` usage in RPC handlers

**`/home/aditya/projects/alpauls-ats/src/rpc/router/admin.ts`** — creating a new user + account:
```ts
// line 81 — user ID
const id = crypto.randomUUID();

// lines 102-118 — inserting user and account
await db.insert(user).values({
  email: normalizedEmail,
  id,                                    // ← crypto.randomUUID()
  name: input.name,
  permissions: input.role === "custom" ? input.permissions : null,
  role: input.role,
  supervisorId: input.supervisorId ?? null,
});

await db.insert(account).values({
  accountId: id,
  id: crypto.randomUUID(),               // ← account ID also crypto.randomUUID()
  password: hashedPassword,
  providerId: "credential",
  userId: id,
