## 3. RPC Middleware — `protectedProcedure` Structure

**File**: `/home/aditya/projects/alpauls-ats/src/rpc/middleware.ts`

```ts
import { ORPCError } from "@orpc/server";

import type { Action, Resource } from "@/lib/auth/access-control";
import { auth } from "@/lib/auth/server";
import type { SubordinateCache } from "@/services/supervisor-hierarchy-service";

import { type AuthContext, base } from "./context";

type PermissionMeta = {
  permission?: { resource: Resource; action: Action };
};

const baseWithMeta = base.$meta<PermissionMeta>({});

export const authMiddleware = baseWithMeta.middleware(
  async ({ context, next }) => {
    const sessionData = await auth.api.getSession({
      headers: context.headers || {},
    });

    if (!sessionData?.session || !sessionData?.user) {
      throw new ORPCError("UNAUTHORIZED", {
        message: "You must be signed in",
      });
    }

    const { session, user } = sessionData;
    const subordinateCache: SubordinateCache = new Map();
    return next({
      context: { session, subordinateCache, user } satisfies AuthContext,
    });
  },
);

export const protectedProcedure = baseWithMeta
  .use(authMiddleware)
  .use(async ({ context, next, procedure }) => {
    const required = procedure["~orpc"].meta.permission;
    if (!required) return next();
    if (
      context.user.permissions.includes(
        `${required.resource}:${required.action}`,
      )
    ) {
      return next();
    }

    throw new ORPCError("FORBIDDEN", {
      data: { requiredPermission: required },
      message: `Missing permission: ${required.resource}:${required.action}`,
    });
  });
```

**Chain structure**:
1. `baseWithMeta` — extends `base` context with `PermissionMeta` type
2. `authMiddleware` — calls `auth.api.getSession()` with headers; throws `UNAUTHORIZED` if no session; enriches context with `{ session, user, subordinateCache }`
3. `protectedProcedure` — applies `authMiddleware`, then a **permission check middleware** that reads `procedure["~orpc"].meta.permission`; if no `permission` meta is set, it passes through; if set, it checks whether `context.user.permissions` includes `resource:action`; throws `FORBIDDEN` if not

---

## 4. RPC Base Context

**File**: `/home/aditya/projects/alpauls-ats/src/rpc/context.ts`

```ts
import { os } from "@orpc/server";

import type { auth } from "@/lib/auth/server";
import type { SubordinateCache } from "@/services/supervisor-hierarchy-service";

export type AuthContext = {
  session: typeof auth.$Infer.Session.session;
  subordinateCache: SubordinateCache;
  user: typeof auth.$Infer.Session.user;
};

export const base = os.$context<{
  headers: HeadersInit | undefined;
}>();
```

**Key points**:
- `base` is an oRPC context initialized with just `{ headers: HeadersInit | undefined }` — the only thing available before authentication
- `AuthContext` is the enriched context type after `authMiddleware` runs — it includes `session`, `user` (with resolved permissions and role from `customSession`), and `subordinateCache` (a `Map` for caching supervisor hierarchy lookups)
- The `user` type in `AuthContext` is inferred from `auth.$Infer.Session.user`, which includes the `permissions` and `role` fields added by the `customSession` plugin
